#pragma once\\\\\n#include <cstdint>\\\\\n#include <cstddef>\\\\\n\\\\n// Correctly defined, simple naive but fixed version (for baseline comparison)\\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\n    for (size_t i = 0; i < M; ++i) {\\n        for (size_t j = 0; j < K; j++) {\\n            float sum = 0.0f;\\n            for (size_t Kp = 0; Kp < K; ++Kp) {\\n                // Extract bit\\\n                uint32_t bit = (B[Kp * (K/32) + j/32] >> (j % 32)) & 1uf;\\\n                float sign = (bit == 1) ? 1f : -1f;\\n                float a = A[i * K + Kp];\\n                sum += a * sign * (float)(B[Kp * (K/32) + j/32] >> (j%32) & 1); // simplified sign handling\\n            }\\n            C[i * K + j] = sum;\\n        }\\n    }\\n}